const fed = $('Get Federation').first().json;
const dirs = Array.isArray(fed.directory_urls) ? fed.directory_urls : [];
// Handle JSON APIs AND js/SSR pages that embed JSON (Next.js __NEXT_DATA__ etc.).
const dir = dirs.find(d => d && ['api_endpoint','js','static'].includes(d.extraction_method) && /^https?:\/\//.test(d.url||''));
if (!dir) return [{ json: { __skip: true, note: 'no extractable directory' } }];

const res = await this.helpers.httpRequest({ method:'GET', url:dir.url, headers:{'User-Agent':'Mozilla/5.0 (compatible; leblovina-n8n)'}, returnFullResponse:true, ignoreHttpStatusErrors:true });
let body = res.body;
let root = null;
if (body && typeof body === 'object') root = body;            // JSON API (auto-parsed)
else {
  const text = String(body || '');
  try { root = JSON.parse(text); }                            // raw JSON as text
  catch(e) {
    const blobs = [];
    const nd = text.match(/<script id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/);
    if (nd) blobs.push(nd[1]);
    const re = /<script[^>]*type=["']application\/json["'][^>]*>([\s\S]*?)<\/script>/g;
    let m; while ((m = re.exec(text))) blobs.push(m[1]);
    root = [];
    for (const b of blobs) { try { root.push(JSON.parse(b)); } catch(_) {} }
  }
}

let best = [];
const walk = (o) => {
  if (Array.isArray(o)) { if (o.length > best.length && o.every(x => x && typeof x === 'object' && !Array.isArray(x))) best = o; for (const x of o) walk(x); }
  else if (o && typeof o === 'object') { for (const k of Object.keys(o)) walk(o[k]); }
};
walk(root);
const sample = best.slice(0, 2);
const keys = best.length ? Object.keys(best[0]) : [];
return [{ json: { sourceUrl: dir.url, count: best.length, keys, sample, clubs: best } }];

