const PB_URL = ($('Config').first().json.pbUrl || '').replace(/\/+$/, '');
const token = $('PB Auth').first().json.token; const pbH = { Authorization: token };
const fed = $('Get Federation').first().json; const fedId = fed.id;
const prep = $('Fetch & prep').first().json;

if (prep.__skip) {
  await this.helpers.httpRequest({ method:'PATCH', url:PB_URL+'/api/collections/federations/records/'+fedId, headers:pbH, body:{ status:'needs_review', notes:prep.note }, json:true });
  return [{ json: { ok:false, note: prep.note } }];
}

const fivb = String(fed.fivb_code || '').toUpperCase();
const country = fed.country || '';
let raw = String($('Map fields').first().json.output || '').trim().replace(/^```(json)?/i,'').replace(/```$/,'').trim();
let map; try { map = JSON.parse(raw); } catch(e) { const m = raw.match(/\{[\s\S]*\}/); map = m ? JSON.parse(m[0]) : {}; }

const g = (row, field) => { const k = map[field]; if (!k) return ''; const v = row[k]; return v==null ? '' : String(v).trim(); };
const uslug = (s) => String(s||'').toLowerCase().normalize('NFKC').replace(/[^\p{L}\p{N}]+/gu,'-').replace(/^-+|-+$/g,'').slice(0,60);
const looksUrlPath = (s) => { s=String(s||'').trim(); return /^https?:\/\//i.test(s) || s.startsWith('/'); };
const baseOrigin = (function(){ const m=String(prep.sourceUrl||'').match(/^(https?:\/\/[^/]+)/i); return m?m[1]:''; })();
// Sandbox-safe (n8n Code node has no global URL): pure string ops.
const urlPath = (s) => { s=String(s||'').trim(); if(!s) return ''; const m=s.match(/^https?:\/\/[^/]+(\/[^?#]*)/i); if(m) return m[1]; return (s.startsWith('/')?s:('/'+s)).split('?')[0].split('#')[0]; };
const normUrl = (u) => { u=(u||'').trim().replace(/^https?:\/\//i,''); if(!u) return ''; if(/[\s,]/.test(u)||!u.includes('.')) return ''; return 'https://'+u; };
const now = new Date().toISOString();
const clubs = prep.clubs || [];
const absol = (u) => { u=String(u||'').trim(); if(!u) return ''; if(/^https?:\/\//i.test(u)) return u; if(u.startsWith('//')) return 'https:'+u; if(u.startsWith('/')) return baseOrigin ? baseOrigin+u : ''; return baseOrigin ? baseOrigin+'/'+u.replace(/^\.?\//,'') : ''; };
const findByKey = async (k) => { const r = await this.helpers.httpRequest({ method:'GET', url:PB_URL+'/api/collections/clubs/records', qs:{ filter:"(dedup_key='"+k+"')", perPage:1 }, headers:pbH, json:true }); return (r.items&&r.items[0])||null; };

let created=0, updated=0, failed=0; const errors=[];
for (const row of clubs) {
  const name = g(row,'name'); if (!name) continue;
  const city = g(row,'city'), region = g(row,'region'), website = normUrl(g(row,'website'));
  const sidRaw = g(row,'source_id');
  const detailRaw = g(row,'detail_url') || (looksUrlPath(sidRaw) ? sidRaw : '');
  const detail = absol(detailRaw);
  const stableId = detailRaw ? urlPath(detailRaw) : (looksUrlPath(sidRaw) ? '' : sidRaw);
  const dedup = stableId ? (fivb+':'+stableId) : (fivb+':'+uslug(name)+':'+uslug(city));
  const payload = { federation:fedId, name, country, region, city, website_url:website, website_source: website?'official_list':'none', detail_url:detail, source_url:prep.sourceUrl, source_club_id:stableId, dedup_key:dedup, last_scraped:now };
  try {
    try { await this.helpers.httpRequest({ method:'POST', url:PB_URL+'/api/collections/clubs/records', headers:pbH, body:Object.assign({status:'new'},payload), json:true }); created++; }
    catch(e) { const ex = await findByKey(dedup); if (ex) { await this.helpers.httpRequest({ method:'PATCH', url:PB_URL+'/api/collections/clubs/records/'+ex.id, headers:pbH, body:payload, json:true }); updated++; } else throw e; }
  } catch(e) { failed++; if (errors.length<10) errors.push({ key:dedup, message:(e&&e.message)||String(e) }); }
}
let fstatus;
if (created+updated>0 && failed===0) fstatus='scraped';
else if (failed>0) fstatus='error';
else fstatus='needs_review';   // fetched/mapped ok but produced zero clubs -> review, not a false 'scraped'
await this.helpers.httpRequest({ method:'PATCH', url:PB_URL+'/api/collections/federations/records/'+fedId, headers:pbH, body:{ status:fstatus, last_scraped:now }, json:true });
return [{ json: { ok: failed===0, federation:fivb, mapping:map, total:clubs.length, created, updated, failed, errors } }];
